@Action
def set_product(userResponse: str) -> str:
    """Returns the product based on the service type."""
    try:
      intent_map = {
          "téléphones mobiles": "Mobile",
          "internet haute vitesse": "Internet",
          "services de télévision": "Télévision",
          "téléphonie d'affaires": "Téléphonie Affaires",
          "téléphone résidentiel": "Téléphonie résidentielle",
          "sécurité résidentielle": "Sécurité résidentielle",
          "voix avantage": "Voix Avantage"
      }

      if not userResponse:
          return "no value"

      userResponse = userResponse.strip().lower()
      intent = intent_map.get(userResponse, "technical-support-vague")
      return intent
    except Exception as e:
        print(f"Something went wrong with the code block execution: {e}")
        return "Code Block Error"

@Action
def set_saved_intent(service: str) -> str:
    """Returns the support intent name based on the service type."""
    try:
      intent_map = {
          "télévision": "tv-support",
          "internet": "internet-support",
          "téléphonie résidentielle": "home-phone-support",
          "téléphonie affaires": "business-phone-support",
          "sécurité résidentielle": "security-support",
          "mobile": "wireless-support",
          "voix avantage":"wireless-support"
      }

      if not service:
          return "no value"

      service = service.strip().lower()
      intent = intent_map.get(service, "technical-support-vague")
      productsMix=state["$session.params.productLabelMixFr"]

      # 🔹 Additional logic for business phone
      if service == "téléphonie affaires" and productsMix:
          if "téléphonie affaires sans fil" in productsMix.lower():
              intent = "wireless-support"

      return intent
      
    except Exception as e:
        print(f"Something went wrong with the code block execution: {e}")
        return "Code Block Error"

@Action
def check_saved_intent(counter: int) -> int:
    """Update counter based on intent and current value"""
    try:
        counter= int(counter)
        intent_map = state["$session.params.forcedSelfServIntent"]
        saved_intent = state["$session.params.savedIntent"]

        if intent_map.get(saved_intent) == True:
            counter += 1
            return counter
        else:
            return counter

    except Exception as e:
        print(f"Something went wrong with the code block execution: {e}")
        return -3
